// src/lib/plugin.ts
var plugin = (def) => ({
  strict: false,
  alwaysApply: false,
  ...def,
  apply: (cldAsset, ctx) => def.apply(cldAsset, ctx, ctx)
});

// src/plugins/version.ts
var VersionPlugin = /* @__PURE__ */ plugin({
  name: "Version",
  supports: "all",
  inferOwnOptions: {},
  props: {
    version: true
  },
  apply: (cldAsset, opts) => {
    const { version } = opts;
    if (typeof version !== "string" && typeof version !== "number") return {};
    cldAsset.setVersion(`${version}`.replace("v", ""));
    return {};
  }
});
export {
  VersionPlugin
};
